package com.chaobo.scm.supplier.infrastructure.persistence.contract;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.domain.contract.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisSupplierContractRepository implements SupplierContractRepository,com.chaobo.scm.supplier.application.contract.SupplierContractReadModelPort{private final SupplierContractMapper m;private final SupplierContractHistoryMapper history;public MyBatisSupplierContractRepository(SupplierContractMapper m,SupplierContractHistoryMapper history){this.m=m;this.history=history;}public Optional<SupplierContractAggregate> find(long id){var r=m.find(id);return r==null?Optional.empty():Optional.of(SupplierContractAggregate.rehydrate(r.id(),r.no(),r.supplier(),r.quote(),r.agreement(),r.type(),r.from(),r.to(),r.status(),r.terms(),r.attachment(),r.reason(),r.version()));}public void save(SupplierContractAggregate a,long op){var r=new SupplierContractMapper.Row(a.id(),a.no(),a.supplierId(),a.quoteId(),a.agreement(),a.type(),a.from(),a.to(),a.status().code(),a.terms(),a.attachment(),a.reason(),a.version());var existing=m.find(a.id());if(existing==null)m.insert(r,op);else{history.snapshot(existing,op);if(m.update(r,a.version()-1,op)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"合同已被更新");}}public Optional<com.chaobo.scm.supplier.application.contract.SupplierContractView> detail(long id){var r=m.find(id);return r==null?Optional.empty():Optional.of(view(r));}public com.chaobo.scm.common.api.PageResult<com.chaobo.scm.supplier.application.contract.SupplierContractView> page(Long s,Integer st,String k,int p,int z){return new com.chaobo.scm.common.api.PageResult<>(p,z,m.count(s,st,k),m.page(s,st,k,(p-1)*z,z).stream().map(this::view).toList());}private com.chaobo.scm.supplier.application.contract.SupplierContractView view(SupplierContractMapper.Row r){var s=ContractStatus.from(r.status());return new com.chaobo.scm.supplier.application.contract.SupplierContractView(r.id(),r.no(),r.supplier(),r.quote(),r.agreement(),r.type(),r.from(),r.to(),s.code(),s.label(),r.attachment(),r.version());}}
